CREATE TABLE IF NOT EXISTS cinedirector_projects (id INT UNSIGNED NOT NULL AUTO_INCREMENT, owner_identifier VARCHAR(64) NOT NULL, name VARCHAR(80) NOT NULL, payload LONGTEXT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (id), KEY owner_updated (owner_identifier, updated_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS cinedirector_backups (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT, project_id INT UNSIGNED NOT NULL, payload LONGTEXT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY(id), KEY project_created(project_id, created_at), CONSTRAINT cinedirector_backup_project FOREIGN KEY(project_id) REFERENCES cinedirector_projects(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS cinedirector_scenes (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT, project_id INT UNSIGNED NOT NULL, name VARCHAR(80) NOT NULL, data JSON NOT NULL, PRIMARY KEY(id), KEY project_id(project_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS cinedirector_actors (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT, project_id INT UNSIGNED NOT NULL, name VARCHAR(80) NOT NULL, model VARCHAR(80) NOT NULL, data JSON NOT NULL, PRIMARY KEY(id), KEY project_id(project_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS cinedirector_animations (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT, owner_identifier VARCHAR(64) NOT NULL, label VARCHAR(80) NOT NULL, dictionary VARCHAR(128) NOT NULL, animation VARCHAR(128) NOT NULL, PRIMARY KEY(id), KEY owner_identifier(owner_identifier)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS cinedirector_camera_presets (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT, owner_identifier VARCHAR(64) NOT NULL, name VARCHAR(80) NOT NULL, data JSON NOT NULL, PRIMARY KEY(id), KEY owner_identifier(owner_identifier)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS cinedirector_favorites (identifier VARCHAR(64) NOT NULL, favorite_type VARCHAR(32) NOT NULL, favorite_key VARCHAR(128) NOT NULL, PRIMARY KEY(identifier,favorite_type,favorite_key)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS cinedirector_user_settings (identifier VARCHAR(64) NOT NULL PRIMARY KEY, settings JSON NOT NULL, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS cinedirector_permissions (identifier VARCHAR(64) NOT NULL PRIMARY KEY, role ENUM('user','moderator','admin') NOT NULL DEFAULT 'user', granted_by VARCHAR(64) NULL, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
